Принудительная коррекция
Некоторые обновления нельзя откладывать независимо от их обычной оценки:
Первое условие означает, что данные стали слишком старыми.
Второе означает, что система больше не доверяет локальной коррекции. Например, после резкого движения камеры в старом кадре могут открыться области, для которых вообще нет корректного изображения.
В таком случае система может:
немедленно запросить свежий тайл;
временно снизить качество соседних областей;
отправить небольшой аварийный патч;
заменить участок упрощённым изображением;
отключить локальную деформацию для проблемной зоны.
Принудительные обновления должны резервировать ресурсы раньше обычной очереди.
Упрощённый планировщик на Rust
Ниже приведён пример, который:
вычисляет приоритет каждого тайла;
определяет допустимый возраст;
вычисляет запас времени и оценку;
сначала выбирает обязательные исправления;
затем добавляет остальные тайлы по убыванию оценки;
учитывает ограничения сети, декодера и композиции.
use std::cmp::Ordering;

#[derive(Clone, Copy)]
struct Factors {
 attention: f64,
 motion: f64,
 input: f64,
 target: f64,
 saliency: f64,
 interface: f64,
}

#[derive(Clone, Copy)]
struct Weights {
 attention: f64,
 motion: f64,
 input: f64,
 target: f64,
 saliency: f64,
 interface: f64,
}

#[derive(Clone)]
struct Tile {
 name: &'static str,
 factors: Factors,

 // Уверенность в текущем локальном изображении.
 confidence: f64,

 // Текущий возраст данных в миллисекундах.
 age_ms: f64,

 // Ожидаемое уменьшение визуальной ошибки.
 delta_error: f64,

 // Стоимость передачи и обработки.
 bytes_kb: f64,
 decode_cost: f64,
 compose_ms: f64,
}

#[derive(Clone, Copy)]
struct Config {
 min_age_ms: f64,
 max_age_ms: f64,
 gamma: f64,
 epsilon: f64,
 critical_confidence: f64,
}

#[derive(Debug)]
struct EvaluatedTile {
 index: usize,
 priority: f64,
 age_limit_ms: f64,
 slack_ms: f64,
 score: f64,
 forced: bool,
}

fn calculate_priority(tile: &Tile, weights: Weights) -> f64 {
 let f = tile.factors;

 let priority =
 weights.attention * f.attention
 + weights.motion * f.motion
 + weights.input * f.input
 + weights.target * f.target
 + weights.saliency * f.saliency
 + weights.interface * f.interface;

 priority.clamp(0.0, 1.0)
}

fn calculate_age_limit(
 priority: f64,
 confidence: f64,
 config: Config,
) -> f64 {
 let extra_age =
 (config.max_age_ms - config.min_age_ms)
 * (1.0 - priority).powf(config.gamma)
 * confidence.clamp(0.0, 1.0);

 config.min_age_ms + extra_age
}

fn evaluate_tile(
 index: usize,
 tile: &Tile,
 weights: Weights,
 config: Config,
) -> EvaluatedTile {
 let priority = calculate_priority(tile, weights);

 let age_limit_ms =
 calculate_age_limit(priority, tile.confidence, config);

 let slack_ms = age_limit_ms - tile.age_ms;

 let denominator =
 tile.bytes_kb
 * (config.epsilon + slack_ms.max(0.0));

 let score = if denominator > 0.0 {
 priority * tile.delta_error / denominator
 } else {
 f64::INFINITY
 };

 let forced =
 tile.age_ms > age_limit_ms
 || tile.confidence < config.critical_confidence;

 EvaluatedTile {
 index,
 priority,
 age_limit_ms,
 slack_ms,
 score,
 forced,
 }
}

fn try_reserve(
 tile: &Tile,
 network_left: &mut f64,
 decode_left: &mut f64,
 compose_left: &mut f64,
) -> bool {
 let fits =
 tile.bytes_kb <= *network_left
 && tile.decode_cost <= *decode_left
 && tile.compose_ms <= *compose_left;

 if !fits {
 return false;
 }

 *network_left -= tile.bytes_kb;
 *decode_left -= tile.decode_cost;
 *compose_left -= tile.compose_ms;

 true
}

